import Data.Char (toLower)
import Data.List (sortBy)
import Data.Ord (comparing)

sortTvShows :: [String] -> [String]
sortTvShows showList = sortBy (comparing (map toLower)) showList

import Data.List.Split (splitOn)
import Data.Char (isSpace)

data MatchResults = MatchResults { wins :: Int, draws :: Int, losses :: Int } deriving (Show, Eq)

trim :: String -> String
trim = f . f where f = reverse . dropWhile isSpace

getMatchResults :: [String] -> MatchResults
getMatchResults results = foldl update (MatchResults 0 0 0) results
  where
    update acc result =
      let [part1, part2] = splitOn "-" result
          [team1, score1Str] = splitOn ":" part1
          [team2, score2Str] = splitOn ":" part2
          score1 = read score1Str :: Int
          score2 = read score2Str :: Int
      in if team1 == "Blues" then
           case compare score1 score2 of
             GT -> acc { wins = wins acc + 1 }
             EQ -> acc { draws = draws acc + 1 }
             LT -> acc { losses = losses acc + 1 }
         else if team2 == "Blues" then
           case compare score2 score1 of
             GT -> acc { wins = wins acc + 1 }
             EQ -> acc { draws = draws acc + 1 }
             LT -> acc { losses = losses acc + 1 }
         else acc

