import Data.List (nub)

removeDuplicates :: [Int] -> [Int]
removeDuplicates = nub

import qualified Data.Map as Map
import Data.Map (Map)
import Data.Char (toLower)
import Data.List (isInfixOf)

findAliases :: String -> [String] -> Map String String
findAliases originalName aliases =
    let canonical = map toLower originalName
        isValid alias = canonical `isInfixOf` map toLower alias
        validAliases = filter isValid aliases
    in Map.fromList [(alias, originalName) | alias <- validAliases]

