{-# LANGUAGE OverloadedStrings #-}
import qualified Data.Map as Map
import Data.Map (Map)
import Data.Scientific (toRealFloat)
import Data.Aeson (Value(..))

calculateAverageAge :: [Map String Value] -> Double
calculateAverageAge employees =
    let extractAge m = case Map.lookup "age" m of
                          Just (Number n) -> Just (toRealFloat n :: Double)
                          _ -> Nothing
        ages = mapMaybe extractAge employees
    in if null ages then 0.0 else sum ages / fromIntegral (length ages)

-- Helper for mapMaybe
import Data.Maybe (mapMaybe)

{-# LANGUAGE OverloadedStrings #-}
import qualified Data.Map.Strict as M
import Data.Map.Strict (Map)
import Data.Aeson (Value(..), object, toJSON)
import Data.Text (Text, pack)
import Data.Maybe (fromMaybe)
import qualified Data.Vector as V

showGui :: [String] -> Maybe (Map String Value) -> Map String Value
showGui taskList maybeOptions =
  let options = M.fromList $ maybe [] M.toList maybeOptions
      -- Log the operation (simulating starting the GUI)
      _ = putStrLn "Showing GUI"
      options' = M.insert "taskList" (toJSON taskList) options
  in options'

