import qualified Data.Set as Set
import Data.List (sort)

extractUniqueDihedralTypes :: [(String, String, String, String)] -> Set String
extractUniqueDihedralTypes dihedrals = Set.fromList $ map dihedralType dihedrals
  where
    dihedralType (a1, a2, a3, a4) =
      let (b, c) = if a2 <= a3 then (a2, a3) else (a3, a2)
      in a1 ++ "-" ++ b ++ "-" ++ c ++ "-" ++ a4

